// Arithmetic.java
// 四則演算の結果を出力するプログラム
public class Arithmetic {
    public static void main(String[] args) {
        int a = 15;
        int b = 4;

        // 足し算
        System.out.println(a + " + " + b + " = " + (a + b));
        // 引き算
        System.out.println(a + " - " + b + " = " + (a - b));
        // 掛け算
        System.out.println(a + " * " + b + " = " + (a * b));
        // 割り算（int同士は小数点以下切り捨て）
        System.out.println(a + " / " + b + " = " + (a / b));
        // 余り
        System.out.println(a + " % " + b + " = " + (a % b));
    }
}

