// GradeCheck.java
// 点数に応じた成績を判定するプログラム
public class GradeCheck {
    public static void main(String[] args) {
        int score = 75;

        System.out.println("点数: " + score);

        // if-else if-else で成績を判定
        if (score >= 90) {
            System.out.println("成績: 優");
