// MultiplicationTable.java
// 九九の表を出力するプログラム
public class MultiplicationTable {
    public static void main(String[] args) {
        // 外側ループ: 段（2〜9）
        for (int i = 2; i <= 9; i++) {
            System.out.print(i + ": ");

            // 内側ループ: 掛ける数（1〜9）
            for (int j = 1; j <= 9; j++) {
                System.out.print(i * j);
                if (j < 9) {
                    System.out.print(" ");
                }
            }

            // 各段の最後に改行
            System.out.println();
        }
    }
}

