public class ShapeDemo {
    public static void main(String[] args) {
        // Shape型の配列にCircleとRectangleを格納
        Shape[] shapes = {
            new Circle(5.0),
            new Rectangle(4.0, 6.0)
        };

        // ポリモーフィズム: 同じメソッド呼び出しで異なる処理が実行される
        for (Shape s : shapes) {
            String type = (s instanceof Circle) ? "円" : "長方形";
            System.out.printf("%sの面積: %.2f%n", type, s.area());
        }
    }
}

