// DivisionSafe.java
// try-catchでゼロ除算を安全に処理するプログラム
public class DivisionSafe {
    public static void main(String[] args) {
        System.out.println("計算を実行します...");

        try {
            // ゼロで割ると ArithmeticException が発生
            int result = 10 / 0;
            System.out.println("結果: " + result);
        } catch (ArithmeticException e) {
            // 例外をキャッチして安全に処理
            System.out.println("ゼロでは割れません");
        }

        // 例外が発生しても処理は続行される
        System.out.println("処理を続行します");
    }
}

// ===== AgeException.java =====

