// ===== AgeValidator.java =====

public class AgeValidator {
    // 年齢を検証するメソッド
    static void validateAge(int age) throws AgeException {
        if (age < 0 || age > 150) {
            throw new AgeException("不正な年齢です: " + age);
        }
        System.out.println("年齢 " + age + ": OK");
    }

    public static void main(String[] args) {
        try {
            validateAge(25);
            validateAge(-5);
        } catch (AgeException e) {
            // エラーメッセージを動的に取得
            System.out.println("エラー: " + e.getMessage());
        }
    }
}

// MultiCatch.java
// マルチキャッチ構文を使ったプログラム
public class MultiCatch {
    public static void main(String[] args) {
        String[] data = {"10", "abc", "30"};

        try {
            // 配列の範囲外アクセスまたは数値変換エラーの可能性
            int value = Integer.parseInt(data[1]);
            System.out.println("値: " + value);
        } catch (ArrayIndexOutOfBoundsException | NumberFormatException e) {
            // 複数の例外を1つの catch で処理
            System.out.println("配列エラーまたは数値変換エラーが発生しました");
        }
    }
}

// ===== ServiceException.java =====

class ServiceException extends Exception {
    // 原因の例外も受け取るコンストラクタ
    ServiceException(String message, Throwable cause) {
        super(message, cause);
    }
}

// ===== ExceptionChainDemo.java =====

public class ExceptionChainDemo {
    static void processData(String input) throws ServiceException {
        try {
            int value = Integer.parseInt(input);
            System.out.println("値: " + value);
        } catch (NumberFormatException e) {
            // 元の例外を原因として新しい例外にラップ
            throw new ServiceException("データ処理に失敗しました", e);
        }
    }

    public static void main(String[] args) {
        try {
            processData("abc");
        } catch (ServiceException e) {
            System.out.println("ServiceException: " + e.getMessage());
            System.out.println("原因: " + e.getCause());
        }
    }
}

