// DateDemo.java
// 日付の計算と書式化を行うプログラム
import java.time.LocalDate;
import java.time.format.DateTimeFormatter;

public class DateDemo {
    public static void main(String[] args) {
        // 今日の日付を取得
        LocalDate today = LocalDate.now();

        // 書式を指定
        DateTimeFormatter fmt = DateTimeFormatter.ofPattern("yyyy年MM月dd日");

        System.out.println("今日: " + today.format(fmt));

        // 30日後の日付
        LocalDate future = today.plusDays(30);
        System.out.println("30日後: " + future.format(fmt));
    }
}

// AnnotationDemo.java
// @Deprecatedアノテーションの使い方を学ぶプログラム
public class AnnotationDemo {

    // 非推奨メソッド（使用すると警告が出る）
    @Deprecated
    static void oldMethod() {
        System.out.println("[非推奨メソッド] 古い処理");
    }

    // 新しいメソッド
    static void newMethod() {
        System.out.println("[新メソッド] 新しい処理");
    }

    @SuppressWarnings("deprecation")
    public static void main(String[] args) {
        oldMethod();  // 非推奨だが呼び出し可能
        newMethod();
    }
}

