// SwitchExpression.java
// switch式（arrow構文）を使うプログラム
public class SwitchExpression {
    public static void main(String[] args) {
        int month = 4;

        // switch式で季節を判定（値を返す）
        String season = switch (month) {
            case 3, 4, 5 -> "春";
            case 6, 7, 8 -> "夏";
            case 9, 10, 11 -> "秋";
            case 12, 1, 2 -> "冬";
            default -> "不明";
        };

        System.out.println(month + "月の季節: " + season);
    }
}

