// ===== AlertDisplay.java =====
public class AlertDisplay implements Observer {
    private final int threshold;
    private boolean alerted = false;

    public AlertDisplay(int threshold) {
        this.threshold = threshold;
    }

    @Override
    public void update(String stockName, int price) {
        if (price > threshold && !alerted) {
            System.out.println("[アラート] " + stockName + " が閾値 " + threshold + " を超えました！現在値: " + price);
            alerted = true;
        } else if (price <= threshold && alerted) {
            System.out.println("[アラート解除] " + stockName + " が閾値 " + threshold + " 以下に戻りました。現在値: " + price);
            alerted = false;
        }
    }
}

