class Account {
    private int balance = 0;

    void deposit(int amount) throws InvalidAmountException {
        if (amount <= 0) {
            throw new InvalidAmountException("金額は正の数を指定してください");
        }
        balance += amount;
        System.out.println("預金: " + amount + "円 → 残高: " + balance + "円");
    }

    void withdraw(int amount) throws InsufficientFundsException, InvalidAmountException {
        if (amount <= 0) {
            throw new InvalidAmountException("金額は正の数を指定してください");
        }
        if (amount > balance) {
            throw new InsufficientFundsException("残高不足です（残高: " + balance + "円）");
        }
        balance -= amount;
        System.out.println("引出: " + amount + "円 → 残高: " + balance + "円");
    }
}

