// ===== HttpClient.java =====
import java.util.Random;

public class HttpClient {
    private final Random random = new Random();
    private int callCount = 0;

    public String request(String url) throws NetworkException {
        callCount++;
        // 最初の2回は失敗をシミュレート
        if (callCount <= 2) {
            throw new RetryableException("接続タイムアウト");
        }
        return "レスポンス 200 OK";
    }
}

// ===== RetryExecutor.java =====
public class RetryExecutor {
    private final int maxRetries;
    private final long retryIntervalMs;

    public RetryExecutor(int maxRetries, long retryIntervalMs) {
        this.maxRetries = maxRetries;
        this.retryIntervalMs = retryIntervalMs;
    }

    @FunctionalInterface
    public interface RetryableAction<T> {
        T execute() throws NetworkException;
    }

    public <T> T execute(RetryableAction<T> action) throws NetworkException {
        NetworkException lastException = null;
        for (int attempt = 1; attempt <= maxRetries; attempt++) {
            try {
                return action.execute();
            } catch (RetryableException e) {
                lastException = e;
                System.out.println("[リトライ " + attempt + "/" + maxRetries + "] "
                    + e.getClass().getSimpleName() + ": " + e.getMessage() + "。リトライします...");
                try {
                    Thread.sleep(retryIntervalMs);
                } catch (InterruptedException ie) {
                    Thread.currentThread().interrupt();
                    throw new NetworkException("中断されました");
                }
            } catch (NetworkException e) {
                throw e; // リトライ不可
            }
        }
        throw lastException;
    }
}

