    static String dayOfWeekJp(DayOfWeek dow) {
        return switch (dow) {
            case MONDAY -> "月曜日";
            case TUESDAY -> "火曜日";
            case WEDNESDAY -> "水曜日";
            case THURSDAY -> "木曜日";
            case FRIDAY -> "金曜日";
            case SATURDAY -> "土曜日";
            case SUNDAY -> "日曜日";
        };
    }

    public static void main(String[] args) {
        LocalDate start = LocalDate.of(2026, 1, 1);
        LocalDate end = LocalDate.of(2026, 3, 31);

        // 2日間の期間を計算
        Period period = Period.between(start, end);

        // 月末日を計算
        LocalDate endOfMonth = start.withDayOfMonth(start.lengthOfMonth());

        System.out.println("開始日: " + start);
        System.out.println("終了日: " + end);
        System.out.println("期間: " + period.getMonths() + "ヶ月" + period.getDays() + "日");
