// PasswordChecker.java
// パスワード強度: String API・char操作の総合演習
public class PasswordChecker {
    static void checkStrength(String password) {
        int score = 0;

        // 1. 長さ（8文字以上）
        if (password.length() >= 8) score++;

        boolean hasUpper = false, hasLower = false;
        boolean hasDigit = false, hasSymbol = false;

        for (int i = 0; i < password.length(); i++) {
            char c = password.charAt(i);
            if (Character.isUpperCase(c)) hasUpper = true;
            else if (Character.isLowerCase(c)) hasLower = true;
            else if (Character.isDigit(c)) hasDigit = true;
            else hasSymbol = true;
        }

        if (hasUpper) score++;
        if (hasLower) score++;
        if (hasDigit) score++;
        if (hasSymbol) score++;

        String level;
        if (score >= 5) level = "強";
        else if (score >= 3) level = "中";
        else level = "弱";

        System.out.println("パスワード: " + password + " → 強度: " + level + "（スコア: " + score + "/5）");
    }

    public static void main(String[] args) {
        checkStrength("abc");
        checkStrength("Hello123");
        checkStrength("P@ssw0rd!");
    }
}

