import java.util.*;
import java.util.regex.*;

public class LogParser {
    private static final Pattern LOG_PATTERN = Pattern.compile(
        "\\[(?<datetime>[\\d-]+ [\\d:]+)] (?<level>\\w+) (?<service>\\w+): (?<message>[^(]+?)(?:\\s*\\((?<params>.+)\\))?"
    );

    record LogEntry(String datetime, String level, String service, String message, String params) {}

    public static void main(String[] args) {
        String[] logs = {
            "[2024-01-15 10:30:00] INFO AuthService: ログイン成功 (user=suzuki)",
            "[2024-01-15 10:30:45] ERROR UserService: ログインに失敗 (user=tanaka)",
            "[2024-01-15 10:31:00] INFO OrderService: 注文完了 (orderId=B456)",
            "[2024-01-15 10:31:10] WARN CacheService: キャッシュミス",
            "[2024-01-15 10:31:20] ERROR PaymentService: 決済エラー (orderId=A123)"
        };

        List<LogEntry> entries = new ArrayList<>();
        for (String log : logs) {
            Matcher m = LOG_PATTERN.matcher(log);
            if (m.matches()) {
                entries.add(new LogEntry(
                    m.group("datetime"), m.group("level"),
                    m.group("service"), m.group("message").trim(),
                    m.group("params")
                ));
            }
        }

        // サマリ
        Map<String, Long> counts = new LinkedHashMap<>();
        for (LogEntry e : entries) {
            counts.merge(e.level(), 1L, Long::sum);
        }
        System.out.println("=== ログサマリ ===");
        counts.forEach((level, count) -> System.out.println(level + ": " + count + "件"));

        // ERROR詳細
        System.out.println("\n=== ERRORログ詳細 ===");
        for (LogEntry e : entries) {
            if ("ERROR".equals(e.level())) {
                String detail = "[" + e.datetime() + "] " + e.service() + ": " + e.message();
                if (e.params() != null) detail += " (" + e.params() + ")";
                System.out.println(detail);
            }
        }
    }
}

