// JdbcPattern.java
// JDBC接続: PreparedStatement の総合演習
import java.sql.*;

public class JdbcPattern {
    public static void main(String[] args) {
        String url = "jdbc:h2:mem:testdb";
        System.out.println("接続URL: " + url);

        try (Connection conn = DriverManager.getConnection(url, "sa", "")) {
            // テーブル作成
            try (Statement stmt = conn.createStatement()) {
                stmt.execute("CREATE TABLE products(id INT PRIMARY KEY, name VARCHAR(50), price INT)");
                stmt.execute("INSERT INTO products VALUES(1, 'Java Pro', 980)");
            }
            System.out.println("スキーマ作成完了");

            // PreparedStatementで検索
            String sql = "SELECT id, name, price FROM products WHERE price <= ?";
            try (PreparedStatement ps = conn.prepareStatement(sql)) {
                ps.setInt(1, 5000);  // ?に値をバインド
                try (ResultSet rs = ps.executeQuery()) {
                    System.out.println("検索結果:");
                    while (rs.next()) {
                        System.out.printf("  ID=%d, Name=%s, Price=%d%n",
                            rs.getInt("id"), rs.getString("name"), rs.getInt("price"));
                    }
                }
            }
        } catch (SQLException e) {
            System.out.println("DBエラー: " + e.getMessage());
        }
    }
}

