// ThreadSafeCounter.java
// スレッドセーフカウンター: synchronized, AtomicInteger の総合演習
import java.util.concurrent.atomic.AtomicInteger;

public class ThreadSafeCounter {
    static int unsafeCount = 0;
    static int safeCount = 0;
    static AtomicInteger atomicCount = new AtomicInteger(0);

    static synchronized void safeIncrement() {
        safeCount++;
    }

    public static void main(String[] args) throws InterruptedException {
        int numThreads = 10;
        int iterations = 1000;

        // === synchronized なし ===
        Thread[] threads1 = new Thread[numThreads];
        for (int i = 0; i < numThreads; i++) {
            threads1[i] = new Thread(() -> {
                for (int j = 0; j < iterations; j++) unsafeCount++;
            });
            threads1[i].start();
        }
        for (Thread t : threads1) t.join();
        System.out.println("=== synchronized なし ===");
        System.out.println("期待値: " + (numThreads * iterations) + ", 実際: " + unsafeCount);

        // === synchronized あり ===
        Thread[] threads2 = new Thread[numThreads];
        for (int i = 0; i < numThreads; i++) {
            threads2[i] = new Thread(() -> {
                for (int j = 0; j < iterations; j++) safeIncrement();
            });
            threads2[i].start();
        }
        for (Thread t : threads2) t.join();
        System.out.println("=== synchronized あり ===");
        System.out.println("期待値: " + (numThreads * iterations) + ", 実際: " + safeCount);

        // === AtomicInteger ===
        Thread[] threads3 = new Thread[numThreads];
        for (int i = 0; i < numThreads; i++) {
            threads3[i] = new Thread(() -> {
                for (int j = 0; j < iterations; j++) atomicCount.incrementAndGet();
            });
            threads3[i].start();
        }
        for (Thread t : threads3) t.join();
        System.out.println("=== AtomicInteger ===");
        System.out.println("期待値: " + (numThreads * iterations) + ", 実際: " + atomicCount.get());
    }
}

// DirectoryExplorer.java
// ディレクトリ探索: NIO2・Stream の総合演習
import java.io.IOException;
import java.nio.file.*;
import java.util.*;
import java.util.stream.*;

public class DirectoryExplorer {
    public static void main(String[] args) throws IOException {
        Path dir = Path.of(".");  // カレントディレクトリ

        System.out.println("=== ディレクトリ探索: " + dir.toAbsolutePath() + " ===");

        // ファイルを拡張子でグルーピング
        try (Stream<Path> walk = Files.walk(dir)) {
            Map<String, List<Path>> grouped = walk
                .filter(Files::isRegularFile)
                .collect(Collectors.groupingBy(p -> {
                    String name = p.getFileName().toString();
                    int dot = name.lastIndexOf('.');
                    return dot > 0 ? name.substring(dot) : "(拡張子なし)";
                }));

            // 各拡張子の情報を表示
            grouped.entrySet().stream()
                .sorted(Map.Entry.comparingByKey())
                .forEach(e -> {
                    long totalSize = e.getValue().stream()
                        .mapToLong(p -> {
                            try { return Files.size(p); }
                            catch (IOException ex) { return 0; }
                        }).sum();
                    System.out.printf("%s ファイル: %d個 (合計: %.1fKB)%n",
                        e.getKey(), e.getValue().size(), totalSize / 1024.0);
                });
        }
    }
}

// ParallelTasks.java
// 並列タスク: ExecutorService・Future の総合演習
import java.util.*;
import java.util.concurrent.*;

public class ParallelTasks {
    public static void main(String[] args) throws Exception {
        // 固定サイズのスレッドプール
        ExecutorService executor = Executors.newFixedThreadPool(3);

        // Callableタスクを定義
        List<Callable<String>> tasks = List.of(
            () -> { Thread.sleep(500);  return "計算完了（値: 100）"; },
            () -> { Thread.sleep(300);  return "計算完了（値: 200）"; },
            () -> { Thread.sleep(100);  return "計算完了（値: 300）"; }
        );

        // タスク送信
        List<Future<String>> futures = new ArrayList<>();
        for (Callable<String> task : tasks) {
            futures.add(executor.submit(task));
        }
        System.out.println("タスク送信: " + futures.size() + "件");

        // 結果取得
        for (int i = 0; i < futures.size(); i++) {
            String result = futures.get(i).get();  // ブロッキング待機
            System.out.println("結果" + (i + 1) + ": " + result);
        }

        executor.shutdown();
        System.out.println("全タスク完了");
    }
}

// ===== Task.java =====
public record Task(int id, String name) {
    public static final Task POISON_PILL = new Task(-1, "STOP");
}

// ===== Producer.java =====
import java.util.concurrent.BlockingQueue;

public class Producer implements Runnable {
    private final BlockingQueue<Task> queue;
    private final int taskCount;

    public Producer(BlockingQueue<Task> queue, int taskCount) {
        this.queue = queue;
        this.taskCount = taskCount;
    }

    @Override
    public void run() {
        try {
            for (int i = 1; i <= taskCount; i++) {
                Task task = new Task(i, "タスク" + i);
                queue.put(task);
                System.out.println("[Producer] タスク投入: " + task);
                Thread.sleep(100);
            }
            queue.put(Task.POISON_PILL);
            System.out.println("[Producer] 全タスク投入完了");
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
    }
}

// ===== Consumer.java =====
import java.util.concurrent.BlockingQueue;

public class Consumer implements Runnable {
    private final BlockingQueue<Task> queue;

    public Consumer(BlockingQueue<Task> queue) {
        this.queue = queue;
    }

    @Override
    public void run() {
        try {
            while (true) {
                Task task = queue.take();
                if (task == Task.POISON_PILL) {
                    System.out.println("[Consumer] 終了シグナル受信。停止します。");
                    break;
                }
                System.out.println("[Consumer] 処理中: " + task);
                Thread.sleep(200); // 処理時間シミュレート
            }
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
    }
}

