// ===== OrderPipeline.java =====
import java.util.concurrent.CompletableFuture;

public class OrderPipeline {

    static String checkStock(String product) {
        sleep(300);
        if ("商品C".equals(product)) {
            throw new RuntimeException("在庫がありません");
        }
        System.out.println("[在庫確認] " + product + ": OK");
        return product;
    }

    static String calculatePrice(String product) {
        sleep(200);
        int basePrice = product.equals("商品A") ? 1000 : 2000;
        int discounted = (int)(basePrice * 0.85);
        System.out.println("[価格計算] " + product + ": " + discounted + "円（15%OFF）");
        return product + ":" + discounted;
    }

    static String processPayment(String data) {
        sleep(500);
        String[] parts = data.split(":");
        System.out.println("[決済完了] " + parts[0] + ": " + parts[1] + "円");
        return "完了";
    }

    static void sleep(long ms) {
        try { Thread.sleep(ms); } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
    }

    public static void main(String[] args) {
        String[] products = {"商品A", "商品B", "商品C"};

        CompletableFuture<?>[] futures = new CompletableFuture[products.length];
        for (int i = 0; i < products.length; i++) {
            String product = products[i];
            futures[i] = CompletableFuture
                .supplyAsync(() -> checkStock(product))
                .thenApplyAsync(OrderPipeline::calculatePrice)
                .thenApplyAsync(OrderPipeline::processPayment)
                .exceptionally(ex -> {
                    System.out.println("[エラー] " + product + ": " + ex.getCause().getMessage());
                    return "エラー";
                });
        }

        CompletableFuture.allOf(futures).join();
        System.out.println("全注文処理完了");
    }
}

