        // module-info.java の内容を設計
        String modelModule = """
            // model/module-info.java
            module com.example.model {
                exports com.example.model;
            }""";

        String serviceModule = """
            // service/module-info.java
            module com.example.service {
                requires transitive com.example.model;
                exports com.example.service;
            }""";

        String appModule = """
            // app/module-info.java
            module com.example.app {
                requires com.example.service;
                // transitive経由でcom.example.modelも利用可能
            }""";

        System.out.println(modelModule);
        System.out.println(serviceModule);
        System.out.println(appModule);

        System.out.println("model: exports com.example.model");
        System.out.println("service: requires model, exports com.example.service");
        System.out.println("app: requires service (transitive→modelも利用可能)");
    }
}

